83	/**
84	 * Execute multi-agent chat with provider abstraction
85	 */
86	async function* executeMultiAgentChat(
87	  request: ChatRequest,
88	  requestAbortControllers: Map<string, AbortController>,
89	  debugMode: boolean = false
90	): AsyncGenerator<StreamResponse> {
91	  try {
92	    // Create abort controller
93	    const abortController = new AbortController();
94	    requestAbortControllers.set(request.requestId, abortController);
95	    
96	    if (debugMode) {
97	      console.debug("[Multi-Agent] Processing request:", {
98	        message: request.message.substring(0, 100) + "...",
99	        availableAgents: request.availableAgents?.map(a => a.id),
100	      });
101	    }
102	    
103	    // Parse agent mentions and commands
104	    const mentionMatches = request.message.match(/@([\w-]+)/g);
105	    const command = parseAgentCommand(request.message);
106	    
107	    if (mentionMatches && mentionMatches.length === 1) {
108	      // Single agent mention - direct execution
109	      const mentionedAgentId = mentionMatches[0].substring(1);
110	      
111	      if (debugMode) {
112	        console.debug(`[Multi-Agent] Single agent mentioned: ${mentionedAgentId}`);
113	      }
114	      
115	      yield* executeSingleAgent(
116	        mentionedAgentId,
117	        request,
118	        command,
119	        abortController,
120	        debugMode
121	      );
122	    } else {
123	      // Multi-agent or orchestration scenario
124	      yield* executeOrchestration(
125	        request,
126	        command,
127	        abortController,
128	        debugMode
129	      );
130	    }
131	    
132	  } catch (error) {
133	    yield {
134	      type: "error",
135	      error: error instanceof Error ? error.message : String(error),
136	    };
137	  } finally {
138	    requestAbortControllers.delete(request.requestId);
139	  }
140	}
