  message: string;
  sessionId?: string;
  requestId: string;
  allowedTools?: string[];
  workingDirectory?: string;
  claudeAuth?: {
    accessToken: string;
    refreshToken: string;
    expiresAt: number;
    userId: string;
    subscriptionType: string;
    account: {
      email_address: string;
      uuid: string;
    };
  };
  availableAgents?: Array<{
    id: string;
