/**
 * Handle a `delegate_task` tool call: run the delegated sub-agent, feed its
 * result back to the delegating agent as a tool_result, and continue the
 * delegating agent's conversation with that result. Handles unknown agents,
 * sub-agent failures, and circular delegation chains.
 */
async function* handleDelegateTask(
  toolUseResponse: ProviderResponse,
  delegatingAgentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[]
): AsyncGenerator<StreamResponse> {
  const { agent_id: targetAgentId, instructions = "" } = parseDelegateTaskInput(
    toolUseResponse.toolInput
  );
  const toolUseId =
    toolUseResponse.toolUseId ??
    `${delegatingAgentId}-delegate-${delegationChain.length}-${Math.random().toString(36).slice(2)}`;

  yield {
    type: "claude_json",
    data: {
      type: "chat_room_message",
      message: {
        type: "command",
        content: `Delegating to ${targetAgentId ?? "unknown agent"}: ${instructions}`,
        agentId: delegatingAgentId,
        timestamp: new Date().toISOString(),
        metadata: { command: "delegate_task" },
      } satisfies ChatRoomMessage,
      session_id: request.sessionId,
    },
  };

  // Circular delegation: target already appears in the chain, or the agent is
  // trying to delegate to itself. Abort the whole delegation - no tool_result
  // is fed back, only a stream-level error.
  if (
    !targetAgentId ||
    targetAgentId === delegatingAgentId ||
    delegationChain.includes(targetAgentId)
  ) {
    yield {
      type: "error",
      error: `Circular delegation detected: ${[...delegationChain, delegatingAgentId, targetAgentId ?? "(missing agent_id)"].join(" -> ")}`,
    };
    return;
  }

  const targetProvider = globalRegistry.getProviderForAgent(targetAgentId);
  const targetConfig = globalRegistry.getAgent(targetAgentId);

  let toolResultContent: string;
  let isError: boolean;

  if (!targetProvider || !targetConfig) {
    // Unknown agent: emit both a stream-level error and an is_error tool_result.
    yield {
      type: "error",
      error: `Agent '${targetAgentId}' not found or provider not available`,
    };
    toolResultContent = `Unknown agent: '${targetAgentId}' not found or provider not available`;
    isError = true;
  } else {
    let accumulatedText = "";
    let subAgentError: string | null = null;
    const visibilityEvents: StreamResponse[] = [];

    try {
      for await (const evt of executeSingleAgent(
        targetAgentId,
        { ...request, message: instructions },
        null,
        abortController,
        debugMode,
        [...delegationChain, delegatingAgentId]
      )) {
        if (evt.type === "claude_json") {
          visibilityEvents.push(evt);
          const data = evt.data as { type?: string; content?: string } | undefined;
          if (data?.type === "assistant" && typeof data.content === "string") {
            accumulatedText += data.content;
          }
        } else if (evt.type === "error") {
          subAgentError = evt.error || "Sub-agent execution failed";
        } else if (evt.type === "aborted") {
          subAgentError = "Sub-agent execution was aborted";
        }
      }
    } catch (err) {
      subAgentError = err instanceof Error ? err.message : String(err);
    }

    // Forward visibility events from the sub-agent's run so the sub-agent's
    // work is visible in the chat room, without surfacing its errors as a
    // stream-level error for this delegation (only the tool_result reflects it).
    yield* visibilityEvents;

    if (subAgentError) {
      toolResultContent = subAgentError;
      isError = true;
    } else {
      toolResultContent = accumulatedText.trim() || "(sub-agent produced no output)";
      isError = false;
    }
  }

  const toolResult = buildToolResultPayload(toolUseId, toolResultContent, isError);

  // Feed the tool_result back to the delegating agent so it can continue.
  yield* executeSingleAgent(
    delegatingAgentId,
    { ...request, message: toolResult },
    command,
    abortController,
    debugMode,
    delegationChain
  );
}

