describe("delegate_task recursive delegation", () => {
  let mockContext: Partial<Context>;
  let requestAbortControllers: Map<string, AbortController>;

  const agents: Record<string, typeof mockAgent> = {
    "test-agent": { ...mockAgent, id: "test-agent" },
    "helper-agent": { ...mockAgent, id: "helper-agent" },
  };

  beforeEach(() => {
    vi.clearAllMocks();
    requestAbortControllers = new Map();

    mockContext = {
      req: { json: vi.fn() } as any,
      var: { config: { debugMode: false } } as any,
    };

    vi.mocked(globalRegistry.getAgent).mockImplementation(
      (id: string) => agents[id]
    );
    vi.mocked(globalRegistry.getProviderForAgent).mockImplementation(
      (id: string) => (agents[id] ? mockProvider : undefined)
    );
  });

  async function readStream(response: Response) {
    const reader = response.body!.getReader();
    const decoder = new TextDecoder();
    let streamData = "";
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      streamData += decoder.decode(value);
    }
    return streamData
      .split("\n")
      .filter((line) => line.trim())
      .map((line) => JSON.parse(line));
  }

  it("runs the delegated agent and feeds its result back to the delegating agent", async () => {
    const chatRequest: ChatRequest = {
      message: "@test-agent please delegate this",
      requestId: "req-delegate-ok",
    };
    vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

    vi.mocked(mockProvider.executeChat).mockImplementation(async function* (
      request: any
    ) {
      if (request.message.includes("please delegate this")) {
        yield {
          type: "tool_use",
          toolName: "delegate_task",
          toolInput: { agent_id: "helper-agent", instructions: "do the sub task" },
          toolUseId: "tu-1",
        };
        return;
      }
      if (request.message === "do the sub task") {
        yield { type: "text", content: "Helper result" };
        yield { type: "done" };
        return;
      }
      // Re-invocation of the delegating agent with the fed-back tool_result
      const parsed = JSON.parse(request.message);
      expect(parsed.type).toBe("tool_result");
      expect(parsed.is_error).toBe(false);
      expect(parsed.content).toBe("Helper result");
      expect(parsed.tool_use_id).toBe("tu-1");
      yield { type: "text", content: "Final answer" };
      yield { type: "done" };
    });

    const response = await handleMultiAgentChatRequest(
      mockContext as Context,
      requestAbortControllers
    );
    const responses = await readStream(response);

    const finalText = responses.find(
      (r) => r.data?.type === "assistant" && r.data?.content === "Final answer"
    );
    expect(finalText).toBeDefined();

    expect(mockProvider.executeChat).toHaveBeenCalledTimes(3);
  });

